#include <print>
#include <cmath>

consteval double compile_time_sqrt(double x) {
    // метод Ньютона — вычисляется только при компиляции
    double r = x;
    for (int i = 0; i < 10; ++i) r = (r + x/r) / 2;
    return r;
}

constexpr double my_sqrt(double x) {
    if consteval {
        return compile_time_sqrt(x); // безопасно: мы в compile-time контексте
    } else {
        return std::sqrt(x); // runtime: используем libm
    }
}

int main() {
    constexpr double ct = my_sqrt(2.0); // путь compile-time
    double rt = my_sqrt(2.0);           // путь runtime
    std::println("compile-time: {:.6f}", ct);
    std::println("runtime:      {:.6f}", rt);
}

#include <print>
#include <string>

// сокращённый шаблон функции — для каждого вызова создаётся экземпляр нужного типа
void describe(const auto& x) {
    std::println("value: {}", x);
}

// перегрузка для string — более специфична, выигрывает для string-аргументов
void describe(const std::string& s) {
    std::println("string of length {}: {}", s.size(), s);
}

// несколько auto-параметров — каждый является отдельным параметром шаблона
auto add(auto a, auto b) {
    return a + b;
}

int main() {
    describe(42);
    describe(3.14);
    describe(std::string{"hello"});

    std::println("add: {}", add(1, 2));
    std::println("add: {}", add(1.5, 2.5));
    std::println("add: {}", add(std::string{"foo"}, std::string{"bar"}));
}
